#!/usr/bin/env python3
"""Set the 10 game sounds (2 MP3 music tracks + 8 card SFX) in assets/assets.json,
ids a117-a126. Run once from your repo root:  python3 apply_audio.py
Backs up to assets.json.bak, replaces those ids, refreshes manifest.json.
Safe to re-run; replaces any earlier audio at these ids.
"""
import json, os, sys, hashlib
HERE=os.path.dirname(os.path.abspath(__file__))
ASSETS=os.path.join(HERE,"assets","assets.json"); MANIFEST=os.path.join(HERE,"manifest.json")
LABELS={"a117": "sfx_card_slide", "a118": "sfx_card_place", "a119": "sfx_card_shove", "a120": "sfx_card_shuffle", "a121": "sfx_book_flip", "a122": "sfx_card_fan", "a123": "sfx_pack_open", "a124": "sfx_pack_take", "a125": "music_thereturn", "a126": "music_hiphop9"}
NEW={
  "a117": "",
  "a118": "",
  "a119": "",
  "a120": "",
  "a121": "",
  "a122": "",
  "a123": "",
  "a124": "",
  "a125": "",
  "a126": "",
}
def main():
    if not os.path.exists(ASSETS): sys.exit(f"[audio] ERROR: {ASSETS} not found. Run from your repo root.")
    A=json.load(open(ASSETS)); bak=ASSETS+".bak"
    if not os.path.exists(bak): json.dump(A,open(bak,"w"),separators=(",",":")); print(f"[audio] backup: {bak}")
    for a,b in NEW.items():
        t="added" if a not in A else ("unchanged" if A[a]==b else "replaced"); A[a]=b
        print(f"[audio] {a}  {LABELS.get(a,a):16s} {t}")
    json.dump(A,open(ASSETS,"w"),separators=(",",":")); print(f"[audio] wrote {ASSETS}")
    if os.path.exists(MANIFEST):
        try:
            m=json.load(open(MANIFEST)); have={r.get("id") for r in m.get("assets",[])}
            for a,b in NEW.items():
                rec={"id":a,"media_type":"audio/mpeg","bytes_b64":len(b),"sha256":hashlib.sha256(b.encode()).hexdigest(),"occurrences":1}
                if a in have:
                    for r in m["assets"]:
                        if r.get("id")==a: r.update(rec)
                else: m.setdefault("assets",[]).append(rec)
            json.dump(m,open(MANIFEST,"w"),indent=1); print("[audio] manifest refreshed")
        except Exception as e: print(f"[audio] (manifest skip: {e})")
    print("\n[audio] Done. Next: swap in the new game.src.html, then python3 build.py")
if __name__=="__main__": main()
